			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Proton&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Isaac Newton&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-size: 14px;&quot;&gt;Laws of Motion and Gravitational Theory&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(32, 33, 36);  &quot;&gt;Rutherford&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;Postulated the &lt;strong&gt;nuclear structure of the atom&lt;/strong&gt;,&lt;/p&gt;

			&lt;p&gt;Discovered alpha and beta rays&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;&lt;strong&gt;प्रोटॉन:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;प्रोटॉन की खोज &lt;strong&gt;गोल्डस्टीन&lt;/strong&gt; ने की थी।&lt;/li&gt;
	&lt;li&gt;प्रोटॉन का नाम &lt;strong&gt;रदरफोर्ड&lt;/strong&gt; ने रखा था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;ऐनोड किरण&lt;/span&gt;&lt;/span&gt;&amp;nbsp;प्रयोग&lt;/strong&gt; से एक प्रोटॉन प्राप्त होता है।&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;&lt;span class=&quot;hin_dict_span&quot; style=&quot;background: 0px 0px rgb(255, 255, 255);   &quot;&gt;&lt;span itemprop=&quot;itemListElement&quot;&gt;धन आवेशित&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;यह &lt;strong&gt;नाभिक&lt;/strong&gt; में मौजूद होता है।&lt;/li&gt;
	&lt;li&gt;इसका आवेश &lt;span style=&quot;font-weight: 700;&quot;&gt;+1.6 &amp;times; 10&lt;/span&gt;&lt;span style=&quot;font-weight: 700; position: relative; line-height: 0; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;-19&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;C&lt;/span&gt; और द्रव्यमान &lt;span style=&quot;font-weight: 700;&quot;&gt;1.672 &amp;times; 10&lt;/span&gt;&lt;span style=&quot;font-weight: 700; position: relative; line-height: 0; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;-27&lt;/span&gt;&amp;nbsp;&lt;strong&gt;किग्रा या 1.00727 u&lt;/strong&gt; के बराबर है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;अतः, हम यह निष्कर्ष निकाल सकते हैं कि प्रोटॉन की खोज &lt;strong&gt;ई. गोल्डस्टीन&lt;/strong&gt; ने की थी।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:330px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;वैज्ञानिक&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;खोज&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;जेम्स चैडविक&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;न्यूट्रॉन&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;जे. जे. थॉमसन&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;इलेक्ट्रॉन&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;यूजीन गोल्डस्टीन&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;प्रोटोन&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;इसाक न्यूटन&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;गति के नियम और गुरुत्वाकर्षण सिद्धांत&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;रदरफोर्ड&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;परमाणु की परमाणु संरचना &lt;/strong&gt;को अभिनिर्धारित किया,&lt;/p&gt;

			&lt;p&gt;अल्फा और बीटा किरणों की खोज की&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Increase in money supply.&lt;/span&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;I&lt;/span&gt;&lt;/u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ncrease in money supply&lt;/span&gt;&amp;nbsp;results in Inflation.&lt;/li&gt;
	&lt;li&gt;Inflation is just a price rise.&lt;/li&gt;
	&lt;li&gt;The reason is that there is more money chasing the same numbers of goods.&lt;/li&gt;
	&lt;li&gt;In India,&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;RBI regulates the money supply and controls inflation through monetary policy.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;A decrease in Money Supply would lead to deflation.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The tightening of interest rates can be an effective tool to control inflation.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्&amp;zwj;तर &lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;मुद्रा&amp;nbsp;आपूर्ति&amp;nbsp;में वृद्धि&lt;/span&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मुद्रा आपूर्ति में वृद्धि &lt;/strong&gt;से मुद्रास्फीति में वृद्धि होती है।&lt;/li&gt;
	&lt;li&gt;महंगाई सिर्फ मूल्य वृद्धि है।&lt;/li&gt;
	&lt;li&gt;इसका कारण यह है कि अधिक मुद्रा, सामान की समान संख्या के लिए उपलब्ध होती&amp;nbsp;है।&lt;/li&gt;
	&lt;li&gt;भारत में,&lt;strong&gt; RBI मुद्रा आपूर्ति को नियंत्रित करता है और मौद्रिक नीति के माध्यम से मुद्रास्फीति को नियंत्रित करता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;मुद्रा आपूर्ति&amp;nbsp;में कमी से अपस्फीति हो सकती है।&lt;/li&gt;
	&lt;li&gt;मुद्रास्फीति को नियंत्रित करने के लिए ब्याज दरों में मजबूती एक प्रभावी उपकरण हो सकता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;​&lt;u&gt;&lt;strong&gt;Fraser Commission&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;In 1902-03&lt;/strong&gt;, a Police Commission was established for the Police reforms under &lt;strong&gt;Sir Andrew Frazer and Lord Curzon&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(34, 34, 34);   text-align: justify;&quot;&gt;&lt;strong&gt;Fraser Commission &lt;/strong&gt;was appointed by &lt;strong&gt;Lord Curzon in the year 1902&lt;/strong&gt;. &lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(34, 34, 34);   text-align: justify;&quot;&gt;Sir Andrew Henderson Leith Fraser was the chairman of this commission.&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;This commission recommended the appointment of Indians at the officer level in the police.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(32, 33, 36);  &quot;&gt;CID is established in 1902 by the British Government, as recommended by&amp;nbsp;&lt;/span&gt;&lt;b style=&quot;color: rgb(32, 33, 36);  &quot;&gt;the Police Commission&lt;/b&gt;&lt;/li&gt;
	&lt;li&gt;Before this Indians could rise only to the ranks of Inspector of Police, the senior N.C.O. position and they were not considered a part of the Indian Imperial Police.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Sir Andrew Frazer &lt;/span&gt;was the&amp;nbsp;&lt;strong&gt;Lieutenant Governor of Bengal from 1903 to 1908&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:330px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Hunter Commission&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;Hunter Education Commission&lt;/strong&gt; was a landmark commission appointed by&lt;strong&gt; Viceroy Lord Ripon&lt;/strong&gt; with objectives to look into the complaints of the non-implementation of the Wood&amp;rsquo;s Despatch of 1854.&lt;/li&gt;
				&lt;li&gt;This commission, headed by&lt;strong&gt; Sir William Wilson Hunter&lt;/strong&gt;, had submitted its report in&lt;strong&gt; 1882.&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Butler Commission&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;Sir Harcourt Butler&lt;/strong&gt; chaired a three-member committee appointed by his Majesty&amp;rsquo;s Government in Britain in 1927 &lt;strong&gt;to inquire into the relationship between the Indian Princely States and the British Government of India.&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;Hartog Commission&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;Sir Philip Joseph Hartog committee&lt;/strong&gt; was appointed by the British Indian government to survey the growth of education in India.&lt;/li&gt;
				&lt;li&gt;The Hartog committee &lt;strong&gt;1929&lt;/strong&gt;, had devoted more attention to mass education than secondary and University education.&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;फ्रेजर आयोग&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:20px;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;1902-03 में&lt;/strong&gt;, &lt;strong&gt;सर एंड्रयू फ्रेजर और लॉर्ड कर्जन&lt;/strong&gt; के तहत पुलिस सुधारों के लिए एक पुलिस आयोग की स्थापना की गई थी।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;फ्रेजर आयोग&lt;/strong&gt; की नियुक्ति &lt;strong&gt;लॉर्ड कर्जन ने वर्ष 1902 में&lt;/strong&gt; की थी।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सर एंड्रयू हेंडरसन लीथ फ्रेजर इस आयोग के अध्यक्ष थे।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इस आयोग ने पुलिस में अधिकारी स्तर पर भारतीयों की नियुक्ति की सिफारिश की।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;CID की स्थापना 1902 में ब्रिटिश सरकार द्वारा की गई थी, जैसा कि &lt;strong&gt;पुलिस आयोग&lt;/strong&gt; द्वारा अनुशंसित किया गया था।&lt;/li&gt;
	&lt;li&gt;इससे पहले भारतीय केवल पुलिस निरीक्षक, वरिष्ठ एन.सी.ओ. पदों तक ही पदोन्नत किए जाते थे&amp;nbsp;और उन्हें भारतीय शाही पुलिस का हिस्सा नहीं माना जाता था।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सर एंड्रयू फ्रेजर&lt;/strong&gt; &lt;strong&gt;1903 से 1908 तक बंगाल के उपराज्यपाल&lt;/strong&gt; थे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:330px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;हंटर&amp;nbsp;आयोग&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;हंटर शिक्षा&amp;nbsp;आयोग&amp;nbsp;वायसराय लॉर्ड रिपन&lt;/strong&gt; द्वारा नियुक्त एक ऐतिहासिक आयोग था, जिसका उद्देश्य 1854 के वुड्स डिस्पैच के गैर-कार्यान्वयन की शिकायतों को देखना था।&lt;/li&gt;
				&lt;li&gt;&lt;strong&gt;सर विलियम विल्सन हंटर&lt;/strong&gt; की अध्यक्षता वाले, इस आयोग ने 1882 में अपनी रिपोर्ट प्रस्तुत की थी।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बटलर आयोग&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;सर हरकोर्ट बटलर&lt;/strong&gt; ने भारतीय रियासतों और भारत की ब्रिटिश सरकार के बीच संबंधों की जांच के लिए 1927 में &lt;strong&gt;ब्रिटेन में महामहिम सरकार द्वारा नियुक्त तीन सदस्यीय समिति की अध्यक्षता की।&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;हार्टोग&amp;nbsp;आयोग&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;भारत में शिक्षा के विकास का सर्वेक्षण करने के लिए ब्रिटिश भारत सरकार द्वारा &lt;strong&gt;सर&lt;/strong&gt; &lt;strong&gt;फिलिप जोसेफ हार्टोग समिति&lt;/strong&gt; की नियुक्ति की गई थी।&lt;/li&gt;
				&lt;li&gt;हार्टोग कमेटी &lt;strong&gt;1929&lt;/strong&gt; ने माध्यमिक और विश्वविद्यालय शिक्षा की तुलना में जन शिक्षा पर अधिक ध्यान दिया था।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;em&gt;&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Playa, Pinnacles, Pot Holes are&amp;nbsp;produced by erosion. Only Levee is not an erosional feature, it is a depositional feature by the river.&lt;/span&gt;&lt;/strong&gt;&lt;/em&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Leeves:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;A levee is a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;natural or artificial wall that blocks water from going where we don&amp;rsquo;t want it to go.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Levees may be used to&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;increase available land for habitation or divert a body of water&lt;/span&gt;&amp;nbsp;so the fertile soil of a river or sea bed may be used for agriculture.&lt;/li&gt;
	&lt;li&gt;They prevent rivers from&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;flooding cities in a storm surge.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;But if a levee breaks, the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;consequences can be disastrous.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Levees are usually&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;made of earth.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;natural movement of a body&lt;/span&gt;&amp;nbsp;of water pushes sediment to the side, creating a natural levee.&lt;/li&gt;
	&lt;li&gt;The banks of a river are often&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;slightly elevated from the river bed.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;Landform&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Characteristics&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Playa&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;It is a&amp;nbsp;&lt;span style=&quot;color: rgb(77, 81, 86);&quot;&gt;flat-floored bottom of an undrained desert basin that becomes at times a&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;shallow lake.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;It&amp;nbsp;&lt;span style=&quot;color: rgb(32, 33, 36);&quot;&gt;is a dry, vegetation-free, flat area at the lowest part of an undrained desert basin.&lt;/span&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Pinnacles&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;Pinnacles&amp;nbsp;are&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(32, 33, 36);&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;steep columns of rocks&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;left by wind&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;It is an individual column of rock, isolated from other rocks or groups of rocks, in the shape of a vertical shaft or spire.&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Pot Holes&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;It is an&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;erosional landform originate by the fluvial action&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;Potholes&amp;nbsp;&lt;span style=&quot;color: rgb(102, 102, 102);&quot;&gt;form mainly in the upper course of the river&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;color: rgb(102, 102, 102);&quot;&gt;Potholes are the direct consequence of vertical erosion and processes of abrasion&lt;u&gt;.&lt;/u&gt;&lt;/span&gt;&lt;/li&gt;
				&lt;li&gt;&lt;span style=&quot;color: rgb(102, 102, 102);&quot;&gt;Over time&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;small depressions&lt;/span&gt;&amp;nbsp;within the bedrock develop&lt;/span&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;&lt;strong&gt;प्लाया, शिखरिका, जलज गर्तिका अपरदन द्वारा निर्मित होते हैं। एकमात्र लेवी एक अपरदनात्मक विशेषता नहीं है, यह नदी द्वारा एक निक्षेपण विशेषता है।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;लेवी&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;:&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;एक लेवी एक&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;प्राकृतिक या कृत्रिम दीवार है जो पानी को वहां जाने से रोकती है जहां हम नहीं जाने देना चाहते हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;लेवियों का उपयोग&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;निवास के लिए उपलब्ध भूमि को बढ़ाने या पानी के एक निकाय को मोड़ने के लिए किया जा सकता है&lt;/span&gt;&amp;nbsp;ताकि कृषि के लिए नदी या समुद्र तल की उपजाऊ मिट्टी का उपयोग किया जा सके।&lt;/li&gt;
	&lt;li&gt;वे&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;तूफानी लहरों में नदियों को शहरों&amp;nbsp;&lt;/span&gt;में बाढ़ आने से रोकते हैं।&lt;/li&gt;
	&lt;li&gt;लेकिन अगर कोई बांध टूटता है, तो&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;परिणाम विनाशकारी हो सकते हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;लेवी आमतौर पर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;पृथ्वी से बने&amp;nbsp;&lt;/span&gt;होते हैं।&lt;/li&gt;
	&lt;li&gt;पानी के&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;निकाय की प्राकृतिक गति&lt;/span&gt;&amp;nbsp;तलछट को एक तरफ धकेलती है, जिससे एक प्राकृतिक लेवी बन जाती है।&lt;/li&gt;
	&lt;li&gt;एक नदी के किनारे&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;अक्सर नदी के तल से थोड़ा ऊपर उठते हैं।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;स्थलाकृति&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;विशेषताएं&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;प्लाया&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;यह एक अप्रशिक्षित रेगिस्तानी घाटी&amp;nbsp;का सपाट-तल वाला तल है जो कई बार &lt;strong&gt;उथली झील&lt;/strong&gt; बन जाता है।&lt;/li&gt;
				&lt;li&gt;यह एक निर्जन रेगिस्तान बेसिन के सबसे निचले भाग में एक सूखा, वनस्पति रहित, समतल क्षेत्र है।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;शिखरिका&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;शिखर&amp;nbsp;प&lt;strong&gt;वन द्वारा छोड़े गए चट्टानों ,के सीधी खड़ी ढालें&amp;nbsp;हैं।&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;सीधी&amp;nbsp;कटाक्ष&amp;nbsp;या शिखर के आकार में,&amp;nbsp;अन्य चट्टानों या चट्टानों के समूह से अलग, चट्टान की एक ढाल होती है&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;जलज गर्तिका&lt;/strong&gt;&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;यह नदी &lt;strong&gt;निक्षेप से उत्पन्न अपर्दनीय स्थलाकृति हैं।&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;जलज गर्तिकाएं नदी के ऊपरी जल मार्ग पर निर्मित होते हैं।&lt;/li&gt;
				&lt;li&gt;गड्ढे ऊर्ध्वाधर कटाव और घर्षण की प्रक्रियाओं का प्रत्यक्ष परिणाम हैं।&lt;/li&gt;
				&lt;li&gt;अधिक समय तक तलशिला में&amp;nbsp;छोटे गड्ढे&amp;nbsp;विकसित होते हैं।&amp;nbsp;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;The Hague&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The&amp;nbsp;International Court of Justice is located in&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Hague, Netherlands&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;The International Court of Justice was&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;established&amp;nbsp;&lt;/span&gt;in&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;June 1945&lt;/span&gt;&amp;nbsp;by the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;Charter of the United Nations&lt;/span&gt;&amp;nbsp;and began work in&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;April 1946.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The official working languages of the&amp;nbsp;International Court of Justice are&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;English and French.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;It is charged with&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;settling legal disputes&lt;/span&gt;&amp;nbsp;submitted to it by&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;states and giving advisory opinions on legal questions from U.N. bodies and agencies.&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

