&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;हेग &lt;/strong&gt;&lt;/u&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;अंतर्राष्ट्रीय न्यायाल &lt;span style=&quot;font-weight: 700;&quot;&gt;हेग, नीदरलैंड&lt;/span&gt; में स्थित है।&lt;/li&gt;
	&lt;li&gt;अंतर्राष्ट्रीय न्यायालय को &lt;span style=&quot;font-weight: 700;&quot;&gt;जून 1945&lt;/span&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;में संयुक्त राष्ट्र&lt;/span&gt; के &lt;span style=&quot;font-weight: 700;&quot;&gt;चार्टर द्वारा स्थापित&lt;/span&gt; किया &lt;span style=&quot;font-weight: 700;&quot;&gt;गया था और इसने अप्रैल 1946&lt;/span&gt; में काम शुरू किया था।&lt;/li&gt;
	&lt;li&gt;अंतर्राष्ट्रीय न्यायालय की आधिकारिक कामकाजी भाषाएँ &lt;span style=&quot;font-weight: 700;&quot;&gt;अंग्रेजी और फ्रेंच हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;इसे राज्यों द्वारा प्रस्तुत &lt;span style=&quot;font-weight: 700;&quot;&gt;कानूनी विवादों&lt;/span&gt; &lt;span style=&quot;font-weight: 700;&quot;&gt;को निपटाने और संयुक्त राष्ट्र निकायों और एजेंसियों से कानूनी सवालों पर सलाहकार राय देने&lt;/span&gt; के लिए बनाया गया&amp;nbsp;है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

